def cart_icon(parser, token):
    def raise_syntax_error():
        choices = '|'.join([item.name for item in CartItems])
        raise TemplateSyntaxError("Template tag '{}' takes one optional argument: {}".format(bits[0], choices))

    bits = token.split_contents()
    if len(bits) > 2:
        raise_syntax_error()
    if len(bits) == 2:
        try:
            with_items = CartItems(bits[1])
        except ValueError:
            raise_syntax_error()
    else:
        with_items = CartItems.without
    return CartIcon(with_items)

def filter_where_by_value_field(
    qs: "QuerySet", field: str, value: Mapping[str, ValueT | Sequence[ValueT]]
):
    if value is None:
        return qs.none()
    if "eq" in value:
        # allow filtering by `None` value
        return qs.filter(**{field: value["eq"]})
    if one_of := value.get("one_of"):
        return qs.filter(**{f"{field}__in": one_of})
    if not_one_of := value.get("not_one_of"):
        return qs.filter(~Q(**{f"{field}__in": not_one_of}))
    return qs.none()

def queryset(self, request, queryset):
        if self.value():
            query = Q()
            for value in SEARCH_OR_SEPARATORS_REGEX.split(self.value()):
                query |= Q(**{"{}__icontains".format(self.field_path): value.strip()})
            return queryset.filter(query)

def get_objects_summary(service_env, content_type_id, objects):
    from django.urls import reverse

    content_type = ContentType.objects.get_for_id(content_type_id)
    opts = content_type.model_class()._meta
    url = reverse("admin:{}_{}_changelist".format(opts.app_label, opts.model_name))
    return {
        "url": "{}?service_env={}".format(url, service_env.id),
        "name": opts.verbose_name,
        "count": len(objects),
    }

