def choices(self, cl):
        yield {
            "selected": False,
            "value": "",
            "display": _("All"),
            "parameter_name": self.field_path,
        }

        for lookup, title in self.choices_list:
            yield {
                "selected": smart_str(lookup) == self.value(),
                "value": lookup,
                "display": title,
                "parameter_name": self.field_path,
