            settings.MAP_IMPORTED_ID_TO_NEW_ID = True
        settings.CHECK_IP_HOSTNAME_ON_SAVE = False
        if options.get("type") == "dir":
            self.from_dir(options)
        elif options.get("type") == "zip":
            self.from_zip(options)
        else:
            self.from_file(options)

def extract_user_from_response(response: dict) -> AbstractBaseUser:
    try:
        user_handle = response.get("response", {}).get("userHandle")
        user_pk = url_str_to_user_pk(websafe_decode(user_handle).decode("utf8"))
    except (ValueError, TypeError, KeyError):
        raise get_adapter().validation_error("incorrect_code")
    user = get_user_model().objects.filter(pk=user_pk).first()
    if not user:
        raise get_adapter().validation_error("incorrect_code")
    return user

def get_handlebars_comment(text: str, i: int) -> str:
    long = text[i : i + 5] == "{{!--" or text[i : i + 6] == "{{~!--"
    end = i + 5
    unclosed_end = 0
    while end <= len(text):
        if text[end - 2 : end] == "}}" and (
            not long or text[end - 4 : end] == "--}}" or text[end - 5 : end] == "--~}}"
        ):
            return text[i:end]
        if not unclosed_end and text[end] == "<":
            unclosed_end = end
        end += 1
    raise TokenizationError("Unclosed comment", text[i:unclosed_end])

def is_ajax(self, request: HttpRequest) -> bool:
        return any(
            [
                request.META.get("HTTP_X_REQUESTED_WITH") == "XMLHttpRequest",
                request.content_type == "application/json",
                request.META.get("HTTP_ACCEPT") == "application/json",
            ]
        )

def _ldap_groups(self):
        groups = {
            v: k for (k, v) in getattr(settings, "AUTH_LDAP_GROUP_MAPPING", {}).items()
        }
        groups.update(
            {
                v: k
                for (k, v) in getattr(settings, "AUTH_LDAP_NESTED_GROUPS", {}).items()
            }
        )
